import{c as s,Q as a,j as n,m as e}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"后端学习路线总览","description":"","frontmatter":{},"headers":[],"relativePath":"backendLearning/01-后端学习路线总览.md","filePath":"backendLearning/01-后端学习路线总览.md","lastUpdated":1778496697000}'),l={name:"backendLearning/01-后端学习路线总览.md"};function d(r,t,p,i,o,c){return a(),n("div",null,[...t[0]||(t[0]=[e(`<h1 id="后端学习路线总览" tabindex="-1">后端学习路线总览 <a class="header-anchor" href="#后端学习路线总览" aria-label="Permalink to &quot;后端学习路线总览&quot;">​</a></h1><p>后端开发不是&quot;学一门语言 + 一个框架&quot;那么简单,它是一整套关于 <strong>数据怎么存、请求怎么处理、服务怎么跑、流量怎么扛</strong> 的工程体系。</p><p>这套教程围绕以下技术栈展开:</p><table tabindex="0"><thead><tr><th>层</th><th>技术</th><th>角色</th></tr></thead><tbody><tr><td>应用框架(JVM)</td><td>Spring Boot</td><td>企业级首选,生态最成熟</td></tr><tr><td>应用框架(Node)</td><td>ElysiaJS(Bun)</td><td>新一代 TS-first,极致性能与 DX</td></tr><tr><td>关系型数据库</td><td>MySQL / PostgreSQL</td><td>业务核心数据</td></tr><tr><td>内存数据库</td><td>Redis</td><td>缓存、分布式锁、限流、消息</td></tr><tr><td>搜索引擎</td><td>Elasticsearch</td><td>全文检索、日志分析</td></tr><tr><td>列存 OLAP</td><td>ClickHouse</td><td>海量数据分析、实时报表</td></tr><tr><td>向量库</td><td>Milvus / pgvector</td><td>LLM RAG、语义检索</td></tr><tr><td>容器</td><td>Docker</td><td>标准化打包与运行环境</td></tr><tr><td>编排</td><td>Kubernetes</td><td>集群调度、弹性伸缩</td></tr><tr><td>CI/CD</td><td>GitHub Actions / ArgoCD</td><td>代码到生产的自动化</td></tr><tr><td>微服务基建</td><td>Nacos / Sentinel / Seata</td><td>配置注册、限流、分布式事务</td></tr><tr><td>数据流转</td><td>Debezium / Flink</td><td>CDC、实时计算</td></tr></tbody></table><hr><h2 id="一、后端到底在做什么" tabindex="-1">一、后端到底在做什么 <a class="header-anchor" href="#一、后端到底在做什么" aria-label="Permalink to &quot;一、后端到底在做什么&quot;">​</a></h2><p>一个最朴素的后端服务,做的就这几件事:</p><ol><li><strong>接收请求</strong>:HTTP / gRPC / WebSocket</li><li><strong>校验参数 &amp; 鉴权</strong>:别让坏数据/非法用户穿透到下游</li><li><strong>执行业务逻辑</strong>:调用其他服务、读写数据库</li><li><strong>返回响应</strong>:JSON / 二进制 / 流</li><li><strong>打日志、上报指标</strong>:出问题能查、能告警</li></ol><p>听起来像 CRUD,但工业级别的难点在 <strong>&quot;高并发下还正确、还快、还稳&quot;</strong>。</p><hr><h2 id="二、技术栈选型直觉" tabindex="-1">二、技术栈选型直觉 <a class="header-anchor" href="#二、技术栈选型直觉" aria-label="Permalink to &quot;二、技术栈选型直觉&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>推荐组合</th></tr></thead><tbody><tr><td>国内中大型公司、强一致业务</td><td>Spring Boot + MySQL + Redis + ES</td></tr><tr><td>创业公司、追求迭代速度</td><td>ElysiaJS / NestJS + PostgreSQL + Redis</td></tr><tr><td>数据分析重、复杂查询多</td><td>PostgreSQL(JSONB / CTE / 窗口函数)</td></tr><tr><td>跨境/轻业务/Serverless</td><td>Bun + Elysia + Postgres(Neon/Supabase)</td></tr></tbody></table><blockquote><p>经验法则:<strong>先选数据库,再选语言</strong>。语言可以换,数据迁移代价巨大。</p></blockquote><hr><h2 id="三、spring-boot-vs-elysiajs" tabindex="-1">三、Spring Boot vs ElysiaJS <a class="header-anchor" href="#三、spring-boot-vs-elysiajs" aria-label="Permalink to &quot;三、Spring Boot vs ElysiaJS&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>Spring Boot</th><th>ElysiaJS</th></tr></thead><tbody><tr><td>语言</td><td>Java / Kotlin</td><td>TypeScript(Bun)</td></tr><tr><td>启动速度</td><td>秒级(GraalVM 可降到毫秒)</td><td>毫秒级</td></tr><tr><td>性能</td><td>高(JIT 预热后)</td><td>极高(Bun + uWebSockets 路由)</td></tr><tr><td>生态</td><td>极成熟,几乎一切都有官方 starter</td><td>年轻但增长快</td></tr><tr><td>学习曲线</td><td>高(IoC、AOP、Bean 生命周期)</td><td>低(写法贴近 Express/Hono)</td></tr><tr><td>招聘市场</td><td>巨大(国内主流)</td><td>小众但前端友好</td></tr></tbody></table><p><strong>怎么学</strong>:学一边重一边。先扎实 Spring Boot 拿到企业级心智模型,再用 Elysia 体会现代 TS 框架的轻量、类型驱动写法,会让你对&quot;框架本质&quot;看得更透。</p><hr><h2 id="四、数据库怎么选" tabindex="-1">四、数据库怎么选 <a class="header-anchor" href="#四、数据库怎么选" aria-label="Permalink to &quot;四、数据库怎么选&quot;">​</a></h2><table tabindex="0"><thead><tr><th>数据库</th><th>强项</th><th>弱点</th></tr></thead><tbody><tr><td>MySQL</td><td>部署简单、生态广、写多读多业务稳</td><td>JSON / 复杂查询 / 物化视图弱</td></tr><tr><td>PostgreSQL</td><td>类型丰富、JSONB、窗口、CTE、扩展强</td><td>单机性能上限略低、连接数昂贵</td></tr><tr><td>Redis</td><td>KV、过期、原子操作、Pub/Sub、Stream</td><td>容量受内存限制</td></tr><tr><td>Elasticsearch</td><td>倒排索引、聚合、全文检索</td><td>资源吃,不适合做主库</td></tr></tbody></table><blockquote><p>关键认知:<strong>Redis 不是数据库的替代品,ES 也不是</strong>。它们是给关系库&quot;开外挂&quot;的,主数据永远在 MySQL/Postgres 里。</p></blockquote><hr><h2 id="五、docker-与-k8s-在这里扮演什么角色" tabindex="-1">五、Docker 与 K8s 在这里扮演什么角色 <a class="header-anchor" href="#五、docker-与-k8s-在这里扮演什么角色" aria-label="Permalink to &quot;五、Docker 与 K8s 在这里扮演什么角色&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具</th><th>解决的问题</th></tr></thead><tbody><tr><td>Docker</td><td>&quot;在我电脑上能跑&quot;——把代码 + 依赖 + 系统打成镜像</td></tr><tr><td>Docker Compose</td><td>单机一键起一组服务(开发环境最常用)</td></tr><tr><td>Kubernetes</td><td>多节点集群:调度、扩缩、滚动发布、自愈</td></tr></tbody></table><p>学习顺序是:<strong>先 Docker、再 Compose、再 K8s</strong>。直接学 K8s 会被概念淹没。</p><hr><h2 id="六、推荐学习路径" tabindex="-1">六、推荐学习路径 <a class="header-anchor" href="#六、推荐学习路径" aria-label="Permalink to &quot;六、推荐学习路径&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    HTTP 与 REST 基础(02)</span></span>
<span class="line"><span>                            ↓</span></span>
<span class="line"><span>       ┌───────────────────────────────────────────┐</span></span>
<span class="line"><span>       ▼                                           ▼</span></span>
<span class="line"><span>  Spring Boot 主线 (03~08)                ElysiaJS 主线 (09~11)</span></span>
<span class="line"><span>  IoC → Web → JPA → Security              路由 → 中间件 → 类型 → 插件</span></span>
<span class="line"><span>       └─────────── 应用层框架 ────────────┘</span></span>
<span class="line"><span>                           ↓</span></span>
<span class="line"><span>       ┌─────────── 数据存储层 ────────────┐</span></span>
<span class="line"><span>       ▼                                  ▼</span></span>
<span class="line"><span>  MySQL (12~15)              PostgreSQL (16~17)</span></span>
<span class="line"><span>                  Redis (18~20)</span></span>
<span class="line"><span>              Elasticsearch (21~23)</span></span>
<span class="line"><span>       MongoDB / 时序 (38)         ClickHouse (39)</span></span>
<span class="line"><span>                           ↓</span></span>
<span class="line"><span>       ┌─────────── 容器与部署 ────────────┐</span></span>
<span class="line"><span>              Docker (24~26) → K8s (27~30)</span></span>
<span class="line"><span>                  CI/CD + GitOps (40)</span></span>
<span class="line"><span>                           ↓</span></span>
<span class="line"><span>       ┌─────────── 微服务体系 ────────────┐</span></span>
<span class="line"><span>   消息队列(31) 微服务(32) API网关(35) gRPC/GraphQL(37)</span></span>
<span class="line"><span>   配置中心 + 注册中心(41)   分布式事务(42)   限流熔断降级(43)</span></span>
<span class="line"><span>                           ↓</span></span>
<span class="line"><span>       ┌─────────── 工程能力 ──────────────┐</span></span>
<span class="line"><span>    监控可观测性(33) 日志(34) 性能压测(36) 任务调度(44)</span></span>
<span class="line"><span>                           ↓</span></span>
<span class="line"><span>       ┌─────────── 数据流转与业务延展 ─────┐</span></span>
<span class="line"><span>       对象存储(45)  CDC 数据同步(46)  流处理(47)</span></span>
<span class="line"><span>                           ↓</span></span>
<span class="line"><span>       ┌─────────── 通信与 AI 时代基建 ─────┐</span></span>
<span class="line"><span>        WebSocket / 实时(49)   向量库 + AI Infra(48)</span></span>
<span class="line"><span>                           ↓</span></span>
<span class="line"><span>       ┌─────────── 工程素养与架构 ─────────┐</span></span>
<span class="line"><span>       测试体系(50)   DDD 与架构模式(51)</span></span>
<span class="line"><span>       JVM 调优与并发(52)   OAuth2/OIDC/SSO(53)</span></span>
<span class="line"><span>       多级缓存与一致性(54)   网络协议深度(55)</span></span>
<span class="line"><span>       API 文档与契约(56)   多租户 SaaS(57)</span></span>
<span class="line"><span>                           ↓</span></span>
<span class="line"><span>       ┌─────────── 平台 / 云原生进阶 ──────┐</span></span>
<span class="line"><span>       IaC(58)   SRE 与混沌工程(59)</span></span>
<span class="line"><span>       Service Mesh 实战(60)</span></span>
<span class="line"><span>                           ↓</span></span>
<span class="line"><span>       ┌─────────── 专业方向(选修)────────┐</span></span>
<span class="line"><span>       图数据库(61)   数据仓库与数据湖(62)</span></span>
<span class="line"><span>       支付与三方(63)   国际化与时区(64)</span></span>
<span class="line"><span>       Serverless 与 Edge(65)   错误处理(66)</span></span></code></pre></div><p><strong>最低成本上手顺序(给只想跑通一个 demo 的人)</strong>:</p><ol><li>装 Docker</li><li><code>docker run</code> 起一个 MySQL + 一个 Redis</li><li>用 Spring Boot 或 Elysia 写一个 <code>/users</code> CRUD</li><li>上 JWT 鉴权</li><li>把缓存接到 Redis</li><li>写 Dockerfile、加 docker-compose.yml</li><li>推到 K8s,做一次滚动发布</li><li>配 GitHub Actions,push 自动部署(40 章)</li><li>接 Nacos 做配置和服务发现(41 章)</li><li>加文件上传走对象存储(45 章)</li></ol><p>走完这一圈,你已经站在初级后端的中位线上了。</p><p><strong>进阶选修包</strong>:</p><ul><li>业务做大 → 分布式事务(42)+ 限流熔断(43)+ 任务调度(44)</li><li>数据做大 → CDC(46)+ 流处理(47)+ ClickHouse(39)</li><li>AI 接入 → 向量库 + RAG(48)+ WebSocket 流式输出(49)</li><li>工程素养 → 测试体系(50)+ DDD 与架构(51)+ 错误处理(66)</li><li>Java 内功 → JVM 调优与并发(52)</li><li>企业级登录 → OAuth2/OIDC/SSO(53)</li><li>性能下一档 → 多级缓存与一致性(54)+ 网络协议深度(55)</li><li>协作工程 → API 文档与契约(56)</li><li>做 SaaS → 多租户架构(57)</li><li>云原生进阶 → IaC(58)+ SRE(59)+ Service Mesh(60)</li><li>专业方向 → 图数据库(61)/ 数据湖仓(62)/ 支付(63)/ 国际化(64)/ Serverless(65)</li></ul><hr><h2 id="七、新手最容易踩的坑" tabindex="-1">七、新手最容易踩的坑 <a class="header-anchor" href="#七、新手最容易踩的坑" aria-label="Permalink to &quot;七、新手最容易踩的坑&quot;">​</a></h2><ol><li><strong>太早追新技术</strong>:别一上来学 Quarkus、GraphQL Federation、Service Mesh,先把 CRUD + 事务 + 缓存吃透</li><li><strong>以为 ORM 就是 SQL</strong>:ORM 是给你提速的工具,不是免去 SQL 思考的捷径,<strong>N+1、慢查询、死锁</strong> 全在 SQL 层</li><li><strong>缓存当成银弹</strong>:不理解 <strong>缓存穿透 / 击穿 / 雪崩 / 一致性</strong> 就上 Redis,迟早出生产事故</li><li><strong>K8s 第一天就上</strong>:中小团队 Docker Compose 足够撑很久,K8s 是&quot;运维平方根成本&quot;,上之前先掂量</li><li><strong>不写日志 / 不看日志</strong>:80% 的线上问题是&quot;翻日志能解决但没人翻&quot;</li></ol><hr><h2 id="八、本系列阅读建议" tabindex="-1">八、本系列阅读建议 <a class="header-anchor" href="#八、本系列阅读建议" aria-label="Permalink to &quot;八、本系列阅读建议&quot;">​</a></h2><ul><li>每章自带可运行的最小代码片段,边读边敲</li><li>Spring Boot / Elysia 章节相对独立,可以只挑一条主线</li><li>数据库章节强烈建议<strong>配合本地真实环境</strong>(用 Docker 起就行)做练习</li><li>K8s 章节建议用 <strong>kind / minikube / k3d</strong> 在本地跑,不要直接拿生产试手</li></ul><p>下一章我们从 <strong>HTTP 与 RESTful</strong> 这个最容易被略过、却决定后端代码味道的话题开始。</p>`,40)])])}const u=s(l,[["render",d]]);export{g as __pageData,u as default};
